// Dev-time sanity check: catches the two ways this pool tends to rot as it grows —
// duplicate question ids, an `attr` that no longer exists on COUNTRIES, or a name
// inside an `fn` predicate's hardcoded list that doesn't match any country record.
(function validateQuestionData() {
  const countryNames = new Set(COUNTRIES.map(c => c.name));
  const seenIds = new Set();

  QUESTION_CATEGORIES.forEach(cat => {
    cat.questions.forEach(q => {
      if (seenIds.has(q.id)) console.warn(`[countries.js] Duplicate question id: ${q.id}`);
      seenIds.add(q.id);

      if (q.attr) {
        const missing = COUNTRIES.filter(c => !(q.attr in c)).map(c => c.name);
        if (missing.length) {
          console.warn(`[countries.js] Question ${q.id} attr "${q.attr}" missing on: ${missing.join(', ')}`);
        }
      }

      if (typeof q.fn === 'function') {
        // Cheap static check: scan the function source for quoted strings and verify
        // any that look like country names actually exist in COUNTRIES.
        const matches = q.fn.toString().match(/"([^"]+)"/g) || [];
        matches.forEach(m => {
          const name = m.slice(1, -1);
          if (/^[A-Z]/.test(name) && !countryNames.has(name) && name.length > 2) {
            console.warn(`[countries.js] Question ${q.id} fn references unknown country "${name}"`);
          }
        });
      }
    });
  });
})();
